B.YX=new A.fb("2","13","\u0926\u0947\u0939\u093f\u0928\u094b\u093d\u0938\u094d\u092e\u093f\u0928\u094d\u092f\u0925\u093e \u0926\u0947\u0939\u0947 \u0915\u094c\u092e\u093e\u0930\u0902 \u092f\u094c\u0935\u0928\u0902 \u091c\u0930\u093e |\n\u0924\u0925\u093e \u0926\u0947\u0939\u093e\u0928\u094d\u0924\u0930\u092a\u094d\u0930\u093e\u092a\u094d\u0924\u093f\u0930\u094d\u0927\u0940\u0930\u0938\u094d\u0924\u0924\u094d\u0930 \u0928 \u092e\u0941\u0939\u094d\u092f\u0924\u093f ||","dehino \u2019smin yath\u0101 dehe kaum\u0101ra\u1e41 yauvana\u1e41 jar\u0101 |\ntath\u0101 deh\u0101ntara-pr\u0101ptir dh\u012bras tatra na muhyati ||","Just as the embodied soul passes from childhood to youth to old age, similarly the soul passes into another body at death.")
B.Z_=new A.fb("2","14","\u092e\u093e\u0924\u094d\u0930\u093e\u0938\u094d\u092a\u0930\u094d\u0936\u093e\u0938\u094d\u0924\u0941 \u0915\u094c\u0928\u094d\u0924\u0947\u092f \u0936\u0940\u0924\u094b\u0937\u094d\u0923\u0938\u0941\u0916\u0926\u0941\u0903\u0916\u0926\u093e\u0903 |\n\u0906\u0917\u092e\u093e\u092a\u093e\u092f\u093f\u0928\u094b\u093d\u0928\u093f\u0924\u094d\u092f\u093e\u0938\u094d\u0924\u093e\u0902\u0938\u094d\u0924\u093f\u0924\u093f\u0915\u094d\u0937\u0938\u094d\u0935 \u092d\u093e\u0930\u0924 ||","m\u0101tr\u0101-spar\u015b\u0101s tu kaunteya \u015b\u012bto\u1e63\u1e47a-sukha-du\u1e25kha-d\u0101\u1e25 |\n\u0101gam\u0101p\u0101yino \u2019nity\u0101s t\u0101\u1e41s titik\u1e63asva bh\u0101rata ||","O son of Kunti, the contact between the senses and objects gives rise to heat, cold, pleasure and pain. They come and go and are temporary.")
B.Z2=new A.fb("2","20","\u0928 \u091c\u093e\u092f\u0924\u0947 \u092e\u094d\u0930\u093f\u092f\u0924\u0947 \u0935\u093e \u0915\u0926\u093e\u091a\u093f\u0928\u094d\n\u0928\u093e\u092f\u0902 \u092d\u0942\u0924\u094d\u0935\u093e \u092d\u0935\u093f\u0924\u093e \u0935\u093e \u0928 \u092d\u0942\u092f\u0903 |\n\u0905\u091c\u094b \u0928\u093f\u0924\u094d\u092f\u0903 \u0936\u093e\u0936\u094d\u0935\u0924\u094b\u093d\u092f\u0902 \u092a\u0941\u0930\u093e\u0923\u094b\n\u0928 \u0939\u0928\u094d\u092f\u0924\u0947 \u0939\u0928\u094d\u092f\u092e\u093e\u0928\u0947 \u0936\u0930\u0940\u0930\u0947 ||","na j\u0101yate mriyate v\u0101 kad\u0101cin\nn\u0101ya\u1e41 bh\u016btv\u0101 bhavit\u0101 v\u0101 na bh\u016bya\u1e25 |\najo nitya\u1e25 \u015b\u0101\u015bvato \u2019ya\u1e41 pur\u0101\u1e47o\nna hanyate hanyam\u0101ne \u015bar\u012bre ||","The soul is never born and never dies. It is eternal, everlasting and ancient. It is not destroyed when the body is destroyed.")
B.Z0=new A.fb("2","22","\u0935\u093e\u0938\u093e\u0902\u0938\u093f \u091c\u0940\u0930\u094d\u0923\u093e\u0928\u093f \u092f\u0925\u093e \u0935\u093f\u0939\u093e\u092f\n\u0928\u0935\u093e\u0928\u093f \u0917\u0943\u0939\u094d\u0923\u093e\u0924\u093f \u0928\u0930\u094b\u093d\u092a\u0930\u093e\u0923\u093f |\n\u0924\u0925\u093e \u0936\u0930\u0940\u0930\u093e\u0923\u093f \u0935\u093f\u0939\u093e\u092f \u091c\u0940\u0930\u094d\u0923\u093e\u0928\u094d\u092f\u0928\u094d\u092f\u093e\u0928\u093f \u0938\u0902\u092f\u093e\u0924\u093f \u0928\u0935\u093e\u0928\u093f \u0926\u0947\u0939\u0940 ||","v\u0101s\u0101\u1e41si j\u012br\u1e47\u0101ni yath\u0101 vih\u0101ya\nnav\u0101ni g\u1e5bh\u1e47\u0101ti naro \u2019par\u0101\u1e47i |\ntath\u0101 \u015bar\u012br\u0101\u1e47i vih\u0101ya j\u012br\u1e47\u0101ny any\u0101ni sa\u1e41y\u0101ti nav\u0101ni deh\u012b ||","As a person puts on new garments, giving up old ones, the soul accepts new bodies leaving the old ones.")
B.Z3=new A.fb("2","27","\u091c\u093e\u0924\u0938\u094d\u092f \u0939\u093f \u0927\u094d\u0930\u0941\u0935\u094b \u092e\u0943\u0924\u094d\u092f\u0941\u0930\u094d\u0927\u094d\u0930\u0941\u0935\u0902 \u091c\u0928\u094d\u092e \u092e\u0943\u0924\u0938\u094d\u092f \u091a |\n\u0924\u0938\u094d\u092e\u093e\u0926\u092a\u0930\u093f\u0939\u093e\u0930\u094d\u092f\u0947\u093d\u0930\u094d\u0925\u0947 \u0928 \u0924\u094d\u0935\u0902 \u0936\u094b\u091a\u093f\u0924\u0941\u092e\u0930\u094d\u0939\u0938\u093f ||","j\u0101tasya hi dhruvo m\u1e5btyur dhruva\u1e41 janma m\u1e5btasya ca |\ntasm\u0101d aparih\u0101rye \u2019rthe na tva\u1e41 \u015bocitum arhasi ||","For one who has taken birth, death is certain; and for one who has died, birth is certain.")
B.Z6=new A.fb("2","47","\u0915\u0930\u094d\u092e\u0923\u094d\u092f\u0947\u0935\u093e\u0927\u093f\u0915\u093e\u0930\u0938\u094d\u0924\u0947 \u092e\u093e \u092b\u0932\u0947\u0937\u0941 \u0915\u0926\u093e\u091a\u0928 |\n\u092e\u093e \u0915\u0930\u094d\u092e\u092b\u0932\u0939\u0947\u0924\u0941\u0930\u094d\u092d\u0942\u0930\u094d\u092e\u093e \u0924\u0947 \u0938\u0919\u094d\u0917\u094b\u093d\u0938\u094d\u0924\u094d\u0935\u0915\u0930\u094d\u092e\u0923\u093f ||","karma\u1e47y-ev\u0101dhik\u0101ras te m\u0101 phale\u1e63u kad\u0101cana |\nm\u0101 karma-phala-hetur bh\u016br m\u0101 te sa\u1e45go \u2019stv akarma\u1e47i ||","You have a right to perform your duties, but never to the fruits of actions.")
B.Z1=new A.fb("2","50","\u092c\u0941\u0926\u094d\u0927\u093f\u092f\u0941\u0915\u094d\u0924\u094b \u091c\u0939\u093e\u0924\u0940\u0939 \u0909\u092d\u0947 \u0938\u0941\u0915\u0943\u0924\u0926\u0941\u0937\u094d\u0915\u0943\u0924\u0947 |\n\u0924\u0938\u094d\u092e\u093e\u0926\u094d\u092f\u094b\u0917\u093e\u092f \u092f\u0941\u091c\u094d\u092f\u0938\u094d\u0935 \u092f\u094b\u0917\u0903 \u0915\u0930\u094d\u092e\u0938\u0941 \u0915\u094c\u0936\u0932\u092e\u094d ||","buddhi-yukto jah\u0101t\u012bha ubhe suk\u1e5bta-du\u1e63k\u1e5bte |\ntasm\u0101d yog\u0101ya yujyasva yoga\u1e25 karmasu kau\u015balam ||","A person engaged in devotional service rids himself of both good and bad reactions. Therefore strive for yoga, which is skill in action.")
B.Z4=new A.fb("3","7","\u092f\u0938\u094d\u0924\u094d\u0935\u093f\u0928\u094d\u0926\u094d\u0930\u093f\u092f\u093e\u0923\u093f \u092e\u0928\u0938\u093e \u0928\u093f\u092f\u092e\u094d\u092f\u093e\u0930\u092d\u0924\u0947\u093d\u0930\u094d\u091c\u0941\u0928 |\n\u0915\u0930\u094d\u092e\u0947\u0928\u094d\u0926\u094d\u0930\u093f\u092f\u0948\u0903 \u0915\u0930\u094d\u092e\u092f\u094b\u0917\u092e\u0938\u0915\u094d\u0924\u0903 \u0938 \u0935\u093f\u0936\u093f\u0937\u094d\u092f\u0924\u0947 ||","yas tv indriy\u0101\u1e47i manas\u0101 niyamy\u0101rabhate \u2019rjuna |\nkarmendriyai\u1e25 karma-yogam asakta\u1e25 sa vi\u015bi\u1e63yate ||","One who controls the senses by the mind and engages in Karma Yoga without attachment excels.")
B.Z5=new A.fb("3","19","\u0924\u0938\u094d\u092e\u093e\u0926\u0938\u0915\u094d\u0924\u0903 \u0938\u0924\u0924\u0902 \u0915\u093e\u0930\u094d\u092f\u0902 \u0915\u0930\u094d\u092e \u0938\u092e\u093e\u091a\u0930 |\n\u0905\u0938\u0915\u094d\u0924\u094b \u0939\u094d\u092f\u093e\u091a\u0930\u0928\u094d\u0915\u0930\u094d\u092e \u092a\u0930\u092e\u093e\u092a\u094d\u0928\u094b\u0924\u093f \u092a\u0941\u0930\u0941\u0937\u0903 ||","tasm\u0101d asakta\u1e25 satata\u1e41 k\u0101rya\u1e41 karma sam\u0101cara |\nasakto hy \u0101caran karma param \u0101pnoti p\u016bru\u1e63a\u1e25 ||","Therefore perform your duty without attachment, for by doing work without attachment one attains the Supreme.")
B.YU=new A.fb("4","7","\u092f\u0926\u093e \u092f\u0926\u093e \u0939\u093f \u0927\u0930\u094d\u092e\u0938\u094d\u092f \u0917\u094d\u0932\u093e\u0928\u093f\u0930\u094d\u092d\u0935\u0924\u093f \u092d\u093e\u0930\u0924 |\n\u0905\u092d\u094d\u092f\u0941\u0924\u094d\u0925\u093e\u0928\u092e\u0927\u0930\u094d\u092e\u0938\u094d\u092f \u0924\u0926\u093e\u0924\u094d\u092e\u093e\u0928\u0902 \u0938\u0943\u091c\u093e\u092e\u094d\u092f\u0939\u092e\u094d ||","yad\u0101 yad\u0101 hi dharmasya gl\u0101nir bhavati bh\u0101rata |\nabhyutth\u0101nam adharmasya tad\u0101tm\u0101na\u1e41 s\u1e5bj\u0101my aham ||","Whenever righteousness declines and unrighteousness rises, I manifest myself.")
B.YS=new A.fb("4","8","\u092a\u0930\u093f\u0924\u094d\u0930\u093e\u0923\u093e\u092f \u0938\u093e\u0927\u0942\u0928\u093e\u0902 \u0935\u093f\u0928\u093e\u0936\u093e\u092f \u091a \u0926\u0941\u0937\u094d\u0915\u0943\u0924\u093e\u092e\u094d |\n\u0927\u0930\u094d\u092e\u0938\u0902\u0938\u094d\u0925\u093e\u092a\u0928\u093e\u0930\u094d\u0925\u093e\u092f \u0938\u092e\u094d\u092d\u0935\u093e\u092e\u093f \u092f\u0941\u0917\u0947 \u092f\u0941\u0917\u0947 ||","paritr\u0101\u1e47\u0101ya s\u0101dh\u016bn\u0101\u1e41 vin\u0101\u015b\u0101ya ca du\u1e63k\u1e5bt\u0101m |\ndharma-sa\u1e41sth\u0101pan\u0101rth\u0101ya sambhav\u0101mi yuge yuge ||","To protect the righteous, destroy the wicked and establish dharma, I appear age after age.")
B.YT=new A.fb("6","5","\u0909\u0926\u094d\u0927\u0930\u0947\u0926\u093e\u0924\u094d\u092e\u0928\u093e\u093d\u0924\u094d\u092e\u093e\u0928\u0902 \u0928\u093e\u0924\u094d\u092e\u093e\u0928\u092e\u0935\u0938\u093e\u0926\u092f\u0947\u0924\u094d |\n\u0906\u0924\u094d\u092e\u0948\u0935 \u0939\u094d\u092f\u093e\u0924\u094d\u092e\u0928\u094b \u092c\u0928\u094d\u0927\u0941\u0930\u093e\u0924\u094d\u092e\u0948\u0935 \u0930\u093f\u092a\u0941\u0930\u093e\u0924\u094d\u092e\u0928\u0903 ||","uddhared \u0101tman\u0101tm\u0101na\u1e41 n\u0101tm\u0101nam avas\u0101dayet |\n\u0101tmaiva hy\u0101tmano bandhur \u0101tmaiva ripur \u0101tmana\u1e25 ||","One must elevate oneself by one\u2019s own mind, not degrade oneself.")
B.YY=new A.fb("6","26","\u092f\u0924\u094b \u092f\u0924\u094b \u0928\u093f\u0936\u094d\u091a\u0930\u0924\u093f \u092e\u0928\u0936\u094d\u091a\u091e\u094d\u091a\u0932\u092e\u0938\u094d\u0925\u093f\u0930\u092e\u094d |\n\u0924\u0924\u0938\u094d\u0924\u0924\u094b \u0928\u093f\u092f\u092e\u094d\u092f\u0948\u0924\u0926\u093e\u0924\u094d\u092e\u0928\u094d\u092f\u0947\u0935 \u0935\u0936\u0902 \u0928\u092f\u0947\u0924\u094d ||","yato yato ni\u015bcarati mana\u015b ca\xf1calam asthiram |\ntatas tato niyamyaitad \u0101tmany eva va\u015ba\u1e41 nayet ||","Wherever the restless mind wanders, bring it back under the control of the self.")
B.YW=new A.fb("9","22","\u0905\u0928\u0928\u094d\u092f\u093e\u0936\u094d\u091a\u093f\u0928\u094d\u0924\u092f\u0928\u094d\u0924\u094b \u092e\u093e\u0902 \u092f\u0947 \u091c\u0928\u093e\u0903 \u092a\u0930\u094d\u092f\u0941\u092a\u093e\u0938\u0924\u0947 |\n\u0924\u0947\u0937\u093e\u0902 \u0928\u093f\u0924\u094d\u092f\u093e\u092d\u093f\u092f\u0941\u0915\u094d\u0924\u093e\u0928\u093e\u0902 \u092f\u094b\u0917\u0915\u094d\u0937\u0947\u092e\u0902 \u0935\u0939\u093e\u092e\u094d\u092f\u0939\u092e\u094d ||","anany\u0101\u015b cintayanto m\u0101\u1e41 ye jan\u0101\u1e25 paryup\u0101sate |\nte\u1e63\u0101\u1e41 nity\u0101bhiyukt\u0101n\u0101\u1e41 yoga-k\u1e63ema\u1e41 vah\u0101my aham ||","Those who worship Me with devotion, I carry what they lack and preserve what they have.")
B.YZ=new A.fb("10","8","\u0905\u0939\u0902 \u0938\u0930\u094d\u0935\u0938\u094d\u092f \u092a\u094d\u0930\u092d\u0935\u094b \u092e\u0924\u094d\u0924\u0903 \u0938\u0930\u094d\u0935\u0902 \u092a\u094d\u0930\u0935\u0930\u094d\u0924\u0924\u0947 |\n\u0907\u0924\u093f \u092e\u0924\u094d\u0935\u093e \u092d\u091c\u0928\u094d\u0924\u0947 \u092e\u093e\u0902 \u092c\u0941\u0927\u093e \u092d\u093e\u0935\u0938\u092e\u0928\u094d\u0935\u093f\u0924\u093e\u0903 ||","aha\u1e41 sarvasya prabhavo matta\u1e25 sarva\u1e41 pravartate |\niti matv\u0101 bhajante m\u0101\u1e41 budh\u0101 bh\u0101va-samanvit\u0101\u1e25 ||","I am the source of all spiritual and material worlds.")
B.YV=new A.fb("12","15","\u092f\u0938\u094d\u092e\u093e\u0928\u094d\u0928\u094b\u0926\u094d\u0935\u093f\u091c\u0924\u0947 \u0932\u094b\u0915\u094b \u0932\u094b\u0915\u093e\u0928\u094d\u0928\u094b\u0926\u094d\u0935\u093f\u091c\u0924\u0947 \u091a \u092f\u0903 |\n\u0939\u0930\u094d\u0937\u093e\u092e\u0930\u094d\u0937\u092d\u092f\u094b\u0926\u094d\u0935\u0947\u0917\u0948\u0930\u094d\u092e\u0941\u0915\u094d\u0924\u094b \u092f\u0903 \u0938 \u091a \u092e\u0947 \u092a\u094d\u0930\u093f\u092f\u0903 ||","yasm\u0101n nodvijate loko lok\u0101n nodvijate ca ya\u1e25 |\nhar\u1e63\u0101mar\u1e63a-bhayodvegair mukto ya\u1e25 sa ca me priya\u1e25 ||","One who is not disturbed by the world and who does not disturb others is dear to Me.")
B.YR=new A.fb("18","66","\u0938\u0930\u094d\u0935\u0927\u0930\u094d\u092e\u093e\u0928\u094d\u092a\u0930\u093f\u0924\u094d\u092f\u091c\u094d\u092f \u092e\u093e\u092e\u0947\u0915\u0902 \u0936\u0930\u0923\u0902 \u0935\u094d\u0930\u091c |\n\u0905\u0939\u0902 \u0924\u094d\u0935\u093e \u0938\u0930\u094d\u0935\u092a\u093e\u092a\u0947\u092d\u094d\u092f\u094b \u092e\u094b\u0915\u094d\u0937\u092f\u093f\u0937\u094d\u092f\u093e\u092e\u093f \u092e\u093e \u0936\u0941\u091a\u0903 ||","sarva-dharm\u0101n parityajya m\u0101m eka\u1e41 \u015bara\u1e47a\u1e41 vraja |\naha\u1e41 tv\u0101 sarva-p\u0101pebhyo mok\u1e63ayi\u1e63y\u0101mi m\u0101 \u015buca\u1e25 ||","Abandon all varieties of religion and surrender unto Me. I shall free you from all sins.")
